parameters.jsonBody:
={{ JSON.stringify({
  contents: [
    {
      parts: [
        { text: "You are SortIt, a waste segregation vision assistant for a kiosk. Classify the item shown in the photo using EXACTLY these four dataset categories, then break the item into its separable physical components. CATEGORY -> BIN RULES: MEDICAL (ANY pharmaceutical item, medicine foils, tablet blister packs, pill strips, syringes, bandages, medicine packaging, masks, gloves) -> bin YELLOW. MEDICAL OVERRIDES ALL MATERIAL RULES: even if a medicine strip or packaging is made of aluminum foil, plastic, or paper, it MUST be classified as bin YELLOW. HAZARDOUS (batteries, chemicals, sharp objects, e-waste, aerosol cans) -> bin RED. RECYCLABLE (clean non-medical cardboard, glass, non-medical metal, paper, non-medical plastic bottles, cans, jars, wrappers, containers) -> bin BLUE. BIODEGRADABLE (food-soiled cardboard/paper, food scraps, organic waste) -> bin GREEN. For composite items, list EACH component separately with its own bin. Respond ONLY with valid JSON, no markdown fences, no extra commentary, in exactly this shape: {\"item_name\": string, \"components\": [{\"part\": string, \"material\": string, \"bin\": \"red\"|\"yellow\"|\"blue\"|\"green\", \"reason\": string}]}" },
        {
          inline_data: {
            mime_type: "image/jpeg",
            data: $json.body.image.replace(/^data:image\/\w+;base64,/, '')
          }
        }
      ]
    }
  ],
  generationConfig: { temperature: 0.0, maxOutputTokens: 500 }
}) }}

parameters.jsCode:
const res = $input.first().json;
let raw = '';
try {
  raw = res.candidates[0].content.parts[0].text;
} catch (e) {
  return [{ json: { item_name: 'Unknown item', components: [], error: 'No response from Gemini' } }];
}
let cleaned = raw.replace(/```json/g, '').replace(/```/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  parsed = { item_name: 'Unknown item', components: [], error: 'Could not parse model response' };
}
return [{ json: parsed }];
